package config

// PointSpec describes a single published MQTT point in cross-integration terms.
// It is provided by the operator (or generated by a consumer system) and keyed
// in Root.PointSpecs by the MQTT point name as it appears in the UDMI trait's
// `points` map. The bacnet driver surfaces these fields verbatim in the
// per-device Metadata.More["point_map"] catalogue announced for each device.
//
// The driver does not interpret any field beyond defaulting; consumers are
// responsible for keeping spec/meaning/type/unit/access consistent with their
// own schedule of systems.
type PointSpec struct {
	// Spec is the consumer's spec/schedule name for the point. When empty the
	// MQTT point name is used as the spec.
	Spec string `json:"spec,omitempty"`
	// Meaning is a free-form semantic label (e.g. "supply.air.temperature").
	Meaning string `json:"meaning,omitempty"`
	// Type is the value type (e.g. "real", "boolean", "enum"). Optional.
	Type string `json:"type,omitempty"`
	// Unit is the engineering unit (e.g. "C", "Pa", "kW"). Optional.
	Unit string `json:"unit,omitempty"`
	// Access is "read" or "read/write". When empty the driver infers it from
	// the BACnet object type backing the point (Output/Value -> "read/write").
	Access string `json:"access,omitempty"`
}
